52	
53	  it('flex value overrides default at canvas resolution time', () => {
54	    const { getByText, getByLabelText, getByTestId, getAllByRole } = renderWithI18n(
55	      <FamilyEditorWorkbench />,
56	    );
57	
58	    // Author one parameter named "Width" with default 1200
59	    fireEvent.click(getAllByRole('button').find((b) => b.textContent === 'Add parameter')!);
