24	/** Resolve a wall's `wallTypeId` to a renderable assembly. Built-in catalog
25	 * entries take precedence over user-authored `wall_type` elements. */
26	export function resolveWallTypeAssembly(
27	  wallTypeId: string,
28	  elementsById?: Record<string, Element>,
29	): WallTypeAssembly | null {
30	  const builtIn = getBuiltInWallType(wallTypeId);
31	  if (builtIn) return builtIn;
32	  if (!elementsById) return null;
33	  const el = elementsById[wallTypeId];
34	  if (!el || el.kind !== 'wall_type') return null;
35	  return {
36	    id: el.id,
37	    name: el.name,
38	    basisLine: (el.basisLine ?? 'center') as 'center' | 'face_interior' | 'face_exterior',
39	    layers: el.layers.map((l) => ({
40	      name: '',
41	      thicknessMm: Number(l.thicknessMm),
42	      materialKey: String(l.materialKey ?? ''),
43	      function: l.function as 'structure' | 'insulation' | 'finish',
44	    })),
45	  };
46	}
47	
48	export type WallElem = Extract<Element, { kind: 'wall' }>;
49	
50	/**
51	 * KRN-09 + FAM-01 — best-effort resolve a `family_instance` curtain-cell
52	 * override into a Three.Group containing the family's authored geometry.
53	 *
54	 * Returns null when the family type is unknown, the family has no
55	 * authored geometry, or resolution throws (cycle, missing param) — the
56	 * caller falls back to the magenta placeholder pane.
57	 *
58	 * The resolved Group is positioned at the cell centre, rotated to the
59	 * wall yaw, and scaled mm → metres so the FAM-01 mm-space geometry
60	 * lines up with the rest of the viewport.
61	 */
62	function tryResolveFamilyInstancePanel(
63	  familyTypeId: string | undefined | null,
64	  cellPosition: THREE.Vector3,
65	  yaw: number,
66	  bimPickId: string,
67	  cellId: string,
68	): THREE.Group | null {
69	  if (!familyTypeId) return null;
70	  const typeEntry = getTypeById(familyTypeId);
71	  const familyDef = typeEntry ? getFamilyById(typeEntry.familyId) : undefined;
72	  if (!familyDef?.geometry?.length) {
73	    return null;
74	  }
75	  try {
76	    const catalog: FamilyCatalogLookup = { [familyDef.id]: familyDef };
77	    // Eagerly hydrate any directly-nested families so the resolver's
78	    // BFS sees the full subgraph from the built-in catalog. Deeper deps
79	    // are picked up recursively as the walk descends.
80	    const seen = new Set<string>([familyDef.id]);
81	    const stack: FamilyDefinition[] = [familyDef];
82	    while (stack.length > 0) {
83	      const def = stack.pop()!;
84	      for (const node of def.geometry ?? []) {
85	        if (node.kind !== 'family_instance_ref') continue;
86	        if (seen.has(node.familyId)) continue;
