89	        catalog[node.familyId] = dep;
90	        seen.add(node.familyId);
91	        stack.push(dep);
92	      }
93	    }
94	    const params = (typeEntry?.parameters ?? {}) as HostParams;
95	    const resolved = resolveFamilyGeometry(familyDef.id, params, catalog);
96	    resolved.scale.set(0.001, 0.001, 0.001);
97	    resolved.position.copy(cellPosition);
98	    resolved.rotation.y = yaw;
99	    resolved.userData.bimPickId = bimPickId;
100	    resolved.userData.curtainCellId = cellId;
101	    resolved.userData.curtainPanelKind = 'family_instance';
102	    resolved.userData.curtainPanelFamilyTypeId = familyTypeId;
103	    return resolved;
104	  } catch (err) {
105	    console.warn(
106	      `[KRN-09] family_instance resolution failed for type '${familyTypeId}'; falling back to placeholder`,
107	      err,
108	    );
109	    return null;
110	  }
