1	/**
2	 * FAM-01 — nested family resolver.
3	 *
4	 * Given a family-authored geometry tree (sweep nodes + nested
5	 * `family_instance_ref` placements) plus a host parameter map and
6	 * a family catalog, walks the tree and produces a Three.js Group
7	 * containing the resolved geometry. Nested-family parameter bindings
8	 * pull their effective values from host params, literals, or
9	 * FAM-04 formulas.
10	 *
11	 * Geometry is emitted in millimetre space — the same convention as
12	 * `meshFromSweep` (FAM-02). Callers scale to scene units.
13	 *
14	 * Cycle detection: BFS up to depth 10. `detectFamilyCycle` is
15	 * intended for save-time validation; the resolver itself also
16	 * throws if it walks past the depth limit, defensively guarding
17	 * against in-memory graphs that bypassed save validation.
18	 */
19	
20	import * as THREE from 'three';
21	import { evaluateFormulaOrThrow } from '../lib/expressionEvaluator';
22	import { meshFromSweep } from './sweepGeometry';
23	import type {
24	  ArrayGeometryNode,
25	  FamilyDefinition,
26	  FamilyGeometryNode,
27	  FamilyInstanceRefNode,
28	  ParameterBinding,
29	  SweepGeometryNode,
30	  VisibilityBinding,
31	} from './types';
32	
33	/** Max recursion depth for nested-family expansion. */
34	export const MAX_NESTED_FAMILY_DEPTH = 10;
35	
36	export type HostParams = Record<string, number | boolean | string>;
37	
38	export type FamilyCatalogLookup = Record<string, FamilyDefinition>;
39	
40	/**
41	 * Compute the effective value of a single binding against the host
42	 * parameter map. Throws on missing host param or formula error.
43	 */
44	export function resolveParameterBinding(
45	  binding: ParameterBinding,
46	  hostParams: HostParams,
47	): number | boolean | string {
48	  if (binding.kind === 'literal') return binding.value;
49	  if (binding.kind === 'host_param') {
50	    if (!Object.prototype.hasOwnProperty.call(hostParams, binding.paramName)) {
51	      throw new Error(`host_param '${binding.paramName}' not present on host`);
52	    }
53	    return hostParams[binding.paramName];
54	  }
55	  // formula
56	  const numericParams: Record<string, number | boolean> = {};
57	  for (const [k, v] of Object.entries(hostParams)) {
58	    if (typeof v === 'number' || typeof v === 'boolean') numericParams[k] = v;
59	  }
60	  return evaluateFormulaOrThrow(binding.expression, numericParams);
61	}
62	
63	/**
64	 * Build the parameter map a nested family will be resolved against:
65	 * start from the family's declared defaults, then layer the
66	 * `parameterBindings` resolved against the host's params.
67	 */
68	function buildNestedParamMap(
69	  def: FamilyDefinition,
70	  bindings: Record<string, ParameterBinding>,
71	  hostParams: HostParams,
72	): HostParams {
73	  const out: HostParams = {};
74	  for (const p of def.params) {
75	    const dv = p.default;
76	    if (typeof dv === 'number' || typeof dv === 'boolean' || typeof dv === 'string') {
77	      out[p.key] = dv;
78	    }
79	  }
80	  for (const [paramName, binding] of Object.entries(bindings)) {
81	    out[paramName] = resolveParameterBinding(binding, hostParams);
82	  }
83	  return out;
84	}
85	
86	/**
87	 * FAM-03 — evaluate a visibility binding against the host params.
88	 *
89	 * Returns true if the bound node should render. Missing param is
90	 * treated as falsy (consistent with `Boolean(undefined) === false`).
91	 */
92	export function isVisibleByBinding(
93	  binding: VisibilityBinding | undefined,
94	  hostParams: HostParams,
95	): boolean {
96	  if (!binding) return true;
97	  const v = hostParams[binding.paramName];
98	  return Boolean(v) === binding.whenTrue;
99	}
100	
101	/**
102	 * Resolve a single geometry node to an Object3D.
103	 *
104	 * Sweep nodes go through FAM-02's `meshFromSweep`. Nested-family
105	 * refs recurse into `resolveNestedFamilyInstance`. Array nodes
106	 * expand into N nested-family copies (FAM-05). Returns null for
107	 * nodes hidden by their `visibilityBinding` (FAM-03).
108	 */
109	function resolveGeometryNode(
110	  node: FamilyGeometryNode,
111	  hostParams: HostParams,
112	  catalog: FamilyCatalogLookup,
113	  depth: number,
114	): THREE.Object3D | null {
115	  // FAM-03: visibility binding short-circuit applies to every node kind.
116	  if (!isVisibleByBinding(node.visibilityBinding, hostParams)) return null;
117	  if (node.kind === 'sweep') {
118	    return resolveSweepNode(node);
119	  }
120	  if (node.kind === 'family_instance_ref') {
121	    return resolveNestedFamilyInstance(node, hostParams, catalog, depth);
122	  }
123	  if (node.kind === 'array') {
124	    return resolveArrayNode(node, hostParams, catalog, depth);
125	  }
126	  return null;
127	}
128	
129	function resolveSweepNode(node: SweepGeometryNode): THREE.Mesh {
130	  const geom = meshFromSweep(node);
131	  return new THREE.Mesh(geom);
132	}
133	
134	/**
135	 * FAM-05 — expand an array node into `count` placements of `target`.
136	 *
137	 * `count = max(1, floor(host_param_value(countParam)))`. Linear mode
138	 * spaces along (axisStart → axisEnd). Radial mode rotates around the
139	 * mid-point of the segment. The center copy (only emitted if a
140	 * `centerVisibilityBinding` is bound and currently truthy) is placed
141	 * at the midpoint with no rotation, regardless of mode.
142	 */
143	export function resolveArrayNode(
144	  node: ArrayGeometryNode,
145	  hostParams: HostParams,
146	  catalog: FamilyCatalogLookup,
147	  depth: number = 0,
148	): THREE.Group {
149	  if (depth > MAX_NESTED_FAMILY_DEPTH) {
150	    throw new Error(
151	      `FAM-05: array node depth ${depth} exceeds MAX_NESTED_FAMILY_DEPTH (${MAX_NESTED_FAMILY_DEPTH}); cycle in family graph?`,
152	    );
153	  }
154	  const group = new THREE.Group();
155	  group.userData.arrayMode = node.mode;
156	  group.userData.countParam = node.countParam;
157	
158	  const rawCount = hostParams[node.countParam];
159	  const numericCount = typeof rawCount === 'number' ? rawCount : Number(rawCount ?? 1);
160	  const count = Math.max(1, Math.floor(Number.isFinite(numericCount) ? numericCount : 1));
161	  group.userData.resolvedCount = count;
162	
163	  const start = new THREE.Vector3(node.axisStart.xMm, node.axisStart.yMm, node.axisStart.zMm);
164	  const end = new THREE.Vector3(node.axisEnd.xMm, node.axisEnd.yMm, node.axisEnd.zMm);
165	  const axisVec = new THREE.Vector3().subVectors(end, start);
166	  const axisLen = axisVec.length();
167	  const axisDir = axisLen > 0 ? axisVec.clone().normalize() : new THREE.Vector3(1, 0, 0);
168	  const center = new THREE.Vector3().addVectors(start, end).multiplyScalar(0.5);
169	
170	  if (node.mode === 'linear') {
171	    let stepMm: number;
172	    if (node.spacing.kind === 'fixed_mm') {
173	      stepMm = node.spacing.mm;
174	    } else {
175	      const total =
176	        typeof hostParams[node.spacing.totalLengthParam] === 'number'
177	          ? (hostParams[node.spacing.totalLengthParam] as number)
178	          : axisLen;
179	      stepMm = count > 1 ? total / (count - 1) : 0;
180	    }
181	    for (let i = 0; i < count; i++) {
182	      const offset = axisDir.clone().multiplyScalar(i * stepMm);
183	      const child = resolveNestedFamilyInstance(node.target, hostParams, catalog, depth + 1);
184	      child.position.add(offset);
185	      group.add(child);
186	    }
187	  } else {
188	    // radial — distribute around an axis from start→end through `center`.
189	    const axis = axisLen > 0 ? axisDir.clone() : new THREE.Vector3(0, 0, 1);
190	    const stepDeg = 360 / count;
191	    for (let i = 0; i < count; i++) {
192	      const angleRad = (i * stepDeg * Math.PI) / 180;
193	      const child = resolveNestedFamilyInstance(node.target, hostParams, catalog, depth + 1);
194	      // Rotate the child's position around the axis through `center`.
195	      const rel = new THREE.Vector3().subVectors(child.position, center);
196	      rel.applyAxisAngle(axis, angleRad);
197	      child.position.copy(center).add(rel);
198	      // Stack the angular rotation onto the target's existing yaw if axis ≈ +Y.
199	      if (Math.abs(axis.y) > Math.abs(axis.x) && Math.abs(axis.y) > Math.abs(axis.z)) {
200	        child.rotation.y += angleRad;
201	      } else {
202	        // For non-Y axes, apply the rotation as a quaternion on top of the child.
203	        const q = new THREE.Quaternion().setFromAxisAngle(axis, angleRad);
204	        child.quaternion.premultiply(q);
205	      }
206	      group.add(child);
207	    }
208	  }
209	
210	  if (
211	    node.centerVisibilityBinding &&
212	    isVisibleByBinding(node.centerVisibilityBinding, hostParams)
213	  ) {
214	    const centerCopy = resolveNestedFamilyInstance(node.target, hostParams, catalog, depth + 1);
215	    centerCopy.position.set(center.x, center.y, center.z);
216	    centerCopy.userData.arrayCenter = true;
217	    group.add(centerCopy);
218	  }
219	
220	  return group;
221	}
222	
223	/**
224	 * FAM-01 entry point. Walks `node.familyId`'s geometry tree using
225	 * effective parameter values derived from `node.parameterBindings`
226	 * + `hostParams`. Returns a Group positioned/rotated per `node`'s
227	 * placement. Hidden subtrees (per `visibilityBinding`) return an
228	 * empty Group rather than null so callers can still attach them.
229	 */
230	export function resolveNestedFamilyInstance(
231	  node: FamilyInstanceRefNode,
232	  hostParams: HostParams,
233	  catalog: FamilyCatalogLookup,
234	  depth: number = 0,
235	): THREE.Group {
236	  if (depth > MAX_NESTED_FAMILY_DEPTH) {
237	    throw new Error(
238	      `FAM-01: nested family depth ${depth} exceeds MAX_NESTED_FAMILY_DEPTH (${MAX_NESTED_FAMILY_DEPTH}); cycle in family graph?`,
239	    );
240	  }
241	  const def = catalog[node.familyId];
242	  if (!def) {
