    """Recover kernel slab-opening id — export names slab voids ``op:<kernelElemId>``."""

    gid = str(getattr(opening, "GlobalId", None) or "")
    nm = str(getattr(opening, "Name", None) or "").strip()
    if nm.startswith("op:"):
        rest = nm[3:].strip()
        if rest:
            return rest
    return _ifc_global_id_slug(gid)


